// frontend/src/features/tasks/taskSlice.js
import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import axios from 'axios';

// Base API
const API_URL = 'http://localhost:3002/api/tasks'; // عدل حسب backend tasks service

// Fetch tasks by projectId
export const fetchTasks = createAsyncThunk(
  'tasks/fetchTasks',
  async ({ projectId }, { rejectWithValue }) => {
    try {
      const res = await axios.get(`${API_URL}?projectId=${projectId}`);
      return res.data; // توقع backend يعطي { tasks: [...] }
    } catch (err) {
      return rejectWithValue(err.response?.data?.message || err.message);
    }
  }
);

// Update task status
export const updateTaskStatus = createAsyncThunk(
  'tasks/updateTaskStatus',
  async ({ id, status }, { rejectWithValue }) => {
    try {
      const res = await axios.patch(`${API_URL}/${id}/status`, { status });
      return res.data; // توقع backend يرجع المهمة المحدثة
    } catch (err) {
      return rejectWithValue(err.response?.data?.message || err.message);
    }
  }
);

// Delete task
export const deleteTask = createAsyncThunk(
  'tasks/deleteTask',
  async (id, { rejectWithValue }) => {
    try {
      await axios.delete(`${API_URL}/${id}`);
      return id;
    } catch (err) {
      return rejectWithValue(err.response?.data?.message || err.message);
    }
  }
);

// Initial state
const initialState = {
  list: [],
  kanban: { todo: [], 'in-progress': [], done: [] },
  loading: false,
  error: null,
};

const taskSlice = createSlice({
  name: 'tasks',
  initialState,
  reducers: {},
  extraReducers: (builder) => {
    // Fetch tasks
    builder.addCase(fetchTasks.pending, (state) => {
      state.loading = true;
      state.error = null;
    });
    builder.addCase(fetchTasks.fulfilled, (state, action) => {
      state.loading = false;
      state.list = action.payload.tasks || [];
      // Organize tasks by status
      state.kanban = { todo: [], 'in-progress': [], done: [] };
      state.list.forEach((t) => {
        if (state.kanban[t.status]) state.kanban[t.status].push(t);
        else state.kanban[t.status] = [t]; // fallback
      });
    });
    builder.addCase(fetchTasks.rejected, (state, action) => {
      state.loading = false;
      state.error = action.payload;
    });

    // Update task status
    builder.addCase(updateTaskStatus.fulfilled, (state, action) => {
      const updatedTask = action.payload;
      // Remove from old status
      Object.values(state.kanban).forEach((col) => {
        const index = col.findIndex((t) => t._id === updatedTask._id);
        if (index > -1) col.splice(index, 1);
      });
      // Add to new status
      if (!state.kanban[updatedTask.status]) state.kanban[updatedTask.status] = [];
      state.kanban[updatedTask.status].push(updatedTask);

      // Update list
      const idx = state.list.findIndex((t) => t._id === updatedTask._id);
      if (idx > -1) state.list[idx] = updatedTask;
    });
    builder.addCase(updateTaskStatus.rejected, (state, action) => {
      state.error = action.payload;
    });

    // Delete task
    builder.addCase(deleteTask.fulfilled, (state, action) => {
      const id = action.payload;
      state.list = state.list.filter((t) => t._id !== id);
      Object.values(state.kanban).forEach((col) => {
        const index = col.findIndex((t) => t._id === id);
        if (index > -1) col.splice(index, 1);
      });
    });
    builder.addCase(deleteTask.rejected, (state, action) => {
      state.error = action.payload;
    });
  },
});

export default taskSlice.reducer;
